package org.eclipse.rdf4j.sail.lmdb.sketch.omni;

/** Set operation for merging compatible OmniSketch instances. */
public final class OmniSketchUnion {
	private final UpdateOmniSketch gadget;

	OmniSketchUnion(final int lgWidth, final int numRows, final int nominalEntries, final long seed) {
		gadget = new UpdateOmniSketch(lgWidth, numRows, nominalEntries, seed);
	}

	/** Creates a new builder. */
	public static OmniSketchBuilder builder() {
		return OmniSketch.builder();
	}

	/** Merges a sketch into this union. Null sketches are ignored. */
	public void update(final OmniSketch sketch) {
		if (sketch != null) {
			gadget.merge(sketch);
		}
	}

	/** Resets this union. */
	public void reset() {
		gadget.reset();
	}

	/** Returns the compact result. */
	public CompactOmniSketch getResult() {
		return gadget.compact();
	}

	/** Returns the number of retained entries in the current result. */
	public int getRetainedEntries() {
		return gadget.getRetainedEntries();
	}

	/** Returns true if no non-empty sketch has been merged. */
	public boolean isEmpty() {
		return gadget.isEmpty();
	}
}
